import{d as e}from"./app.2e1eaa90.js";const a={},r=e('<h1 id="其他内置-api" tabindex="-1"><a class="header-anchor" href="#其他内置-api" aria-hidden="true">#</a> 其他内置 API</h1><h2 id="观察者对象" tabindex="-1"><a class="header-anchor" href="#观察者对象" aria-hidden="true">#</a> 观察者对象</h2><h3 id="observe-target-update-label" tabindex="-1"><a class="header-anchor" href="#observe-target-update-label" aria-hidden="true">#</a> observe(target, update?, label?)</h3><ul><li><strong>target:</strong> <code>T extends object</code> 要观测的对象</li><li><strong>update:</strong> <code>(diff: Partial&lt;T&gt;) =&gt; R</code> 更新回调函数</li><li><strong>label:</strong> <code>string</code> 对象的标签，用于标识</li><li>返回值: <code>Observed&lt;T&gt;</code></li></ul><p>创建一个观察者对象。目前只支持从普通对象创建（不支持 Array / Set / Map）。</p><h3 id="observed-diff" tabindex="-1"><a class="header-anchor" href="#observed-diff" aria-hidden="true">#</a> observed._diff</h3><p>观察者当前的对象变化。</p><h3 id="observed-merge-source" tabindex="-1"><a class="header-anchor" href="#observed-merge-source" aria-hidden="true">#</a> observed._merge(source)</h3><ul><li><strong>source:</strong> <code>object</code> 要合并的对象</li><li>返回值: <code>this</code></li></ul><p>将某些属性合并入当前观察者，不会触发 diff 更新。</p><h3 id="observed-update" tabindex="-1"><a class="header-anchor" href="#observed-update" aria-hidden="true">#</a> observed._update()</h3><ul><li>返回值: <code>R</code></li></ul><p>更新观察者对象，同时清除 diff。</p><h2 id="模板操作" tabindex="-1"><a class="header-anchor" href="#模板操作" aria-hidden="true">#</a> 模板操作</h2><h3 id="template-path-params" tabindex="-1"><a class="header-anchor" href="#template-path-params" aria-hidden="true">#</a> template(path, ...params)</h3><ul><li><strong>path:</strong> <code>string</code> 模板路径</li><li><strong>params:</strong> <code>any[]</code> 参数列表</li><li>返回值: <code>string</code> 生成的字符串</li></ul><p>根据模板路径返回插值后的字符串。如果路径不存在将会返回路径本身。</p><h3 id="template-set-path-value" tabindex="-1"><a class="header-anchor" href="#template-set-path-value" aria-hidden="true">#</a> template.set(path, value)</h3><ul><li><strong>path:</strong> <code>string</code> 模板路径</li><li><strong>value:</strong> <code>string | object</code> 模板字符串</li><li>返回值: <code>void</code></li></ul><p>定义模板字符串。如果 <code>value</code> 是一个对象，则会将 <code>path</code> 作为前缀添加到每个路径中。</p><h3 id="template-get-path" tabindex="-1"><a class="header-anchor" href="#template-get-path" aria-hidden="true">#</a> template.get(path)</h3><ul><li><strong>path:</strong> <code>string</code> 模板路径</li><li>返回值: <code>string</code> 模板字符串</li></ul><p>根据模板路径返回模板字符串。如果路径不存在将会返回路径本身。</p><h3 id="template-format-source-params" tabindex="-1"><a class="header-anchor" href="#template-format-source-params" aria-hidden="true">#</a> template.format(source, ...params)</h3><ul><li><strong>source:</strong> <code>string</code> 模板字符串</li><li><strong>params:</strong> <code>any[]</code> 参数列表</li><li>返回值: <code>string</code> 生成的字符串</li></ul><p>使用模板语法插值。</p><h2 id="输出日志" tabindex="-1"><a class="header-anchor" href="#输出日志" aria-hidden="true">#</a> 输出日志</h2><h3 id="new-logger-name" tabindex="-1"><a class="header-anchor" href="#new-logger-name" aria-hidden="true">#</a> new Logger(name)</h3><h3 id="logger-level" tabindex="-1"><a class="header-anchor" href="#logger-level" aria-hidden="true">#</a> logger.level</h3><h3 id="logger-extend" tabindex="-1"><a class="header-anchor" href="#logger-extend" aria-hidden="true">#</a> logger.extend()</h3><h3 id="logger-error" tabindex="-1"><a class="header-anchor" href="#logger-error" aria-hidden="true">#</a> logger.error()</h3><h3 id="logger-success" tabindex="-1"><a class="header-anchor" href="#logger-success" aria-hidden="true">#</a> logger.success()</h3><h3 id="logger-warn" tabindex="-1"><a class="header-anchor" href="#logger-warn" aria-hidden="true">#</a> logger.warn()</h3><h3 id="logger-info" tabindex="-1"><a class="header-anchor" href="#logger-info" aria-hidden="true">#</a> logger.info()</h3><h3 id="logger-debug" tabindex="-1"><a class="header-anchor" href="#logger-debug" aria-hidden="true">#</a> logger.debug()</h3>',35);a.render=function(e,a){return r};export default a;
